mapper.select:
SELECT a.id, a.commodity_no, a.commodity_name, IFNULL(a.color,'无') AS color, a.size1-(SELECT IFNULL(sum(b.size1),0) from jsh_sample_management_log b WHERE a.id=b.sample_id and b.delete_flag=0) as size1 , a.size2-(SELECT IFNULL(sum(b.size2),0) from jsh_sample_management_log b WHERE a.id=b.sample_id and b.delete_flag=0) as size2 , a.size3-(SELECT IFNULL(sum(b.size3),0) from jsh_sample_management_log b WHERE a.id=b.sample_id and b.delete_flag=0) as size3 , a.size4-(SELECT IFNULL(sum(b.size4),0) from jsh_sample_management_log b WHERE a.id=b.sample_id and b.delete_flag=0) as size4 , a.size5-(SELECT IFNULL(sum(b.size5),0) from jsh_sample_management_log b WHERE a.id=b.sample_id and b.delete_flag=0) as size5 , a.size6-(SELECT IFNULL(sum(b.size6),0) from jsh_sample_management_log b WHERE a.id=b.sample_id and b.delete_flag=0) as size6 , a.size7-(SELECT IFNULL(sum(b.size7),0) from jsh_sample_management_log b WHERE a.id=b.sample_id and b.delete_flag=0) as size7 , a.size8-(SELECT IFNULL(sum(b.size8),0) from jsh_sample_management_log b WHERE a.id=b.sample_id and b.delete_flag=0) as size8 , a.size9-(SELECT IFNULL(sum(b.size9),0) from jsh_sample_management_log b WHERE a.id=b.sample_id and b.delete_flag=0) as size9 , a.size10-(SELECT IFNULL(sum(b.size10),0) from jsh_sample_management_log b WHERE a.id=b.sample_id and b.delete_flag=0) as size10 , a.size11-(SELECT IFNULL(sum(b.size11),0) from jsh_sample_management_log b WHERE a.id=b.sample_id and b.delete_flag=0) as size11 , a.numbers-(SELECT IFNULL(sum(b.numbers),0) from jsh_sample_management_log b WHERE a.id=b.sample_id and b.delete_flag=0) as numbers, a.in_time, a.price, a.remark FROM jsh_sample_management a WHERE a.delete_flag=0
AND a.commodity_no like concat('%',#{request.commodityNo},'%')
AND a.id = #{request.id}
AND a.commodity_name like concat('%',#{request.commodityName},'%')
AND a.color = #{request.color}
AND date_format(a.in_time,'%Y-%m-%d') = #{request.inTimeStr}
AND a.price = #{request.price}

